next(value: T) {
  errorContext(() => {
    this._throwIfClosed();
    if (!this.isStopped) {
      if (!this.currentObservers) {
        this.currentObservers = Array.from(this.observers);
      }
      for (const observer of this.currentObservers) {
        observer.next(value);
      }
    }
  });
}

complete() {
  errorContext(() => {
    this._throwIfClosed();
    if (!this.isStopped) {
      this.isStopped = true;
      const { observers } = this;
      while (observers.length) {
        observers.shift()!.complete();
      }
    }
  });
}

